import assert from "node:assert/strict";
import { readFileSync } from "node:fs";
import test from "node:test";
import vm from "node:vm";

const html = readFileSync(new URL("../index.html", import.meta.url), "utf8");
const script = html.match(/<script>\s*([\s\S]*?)\s*<\/script>/)[1];

test("filters the expense list by selected category", () => {
  const currentMonth = monthKey(new Date());
  const env = bootApp([
    expense({ id: "1", amountCents: 1200, category: "Groceries", date: currentMonth + "-04" }),
    expense({ id: "2", amountCents: 890, category: "Transport", date: currentMonth + "-05" }),
    expense({ id: "3", amountCents: 550, category: "Groceries", date: currentMonth + "-06" })
  ]);

  assert.deepEqual(optionValues(env.elements.categoryFilter), ["", "Groceries", "Transport"]);

  env.elements.categoryFilter.value = "Groceries";
  env.elements.categoryFilter.dispatchEvent({ type: "change" });

  assert.equal(env.elements.expenseRows.children.length, 2);
  assert.deepEqual(rowCategories(env.elements.expenseRows), ["Groceries", "Groceries"]);
  assert.equal(env.elements.expenseCount.textContent, "2 of 3 entries");
});

test("shows current-month totals grouped by category", () => {
  const now = new Date();
  const currentMonth = monthKey(now);
  const previousMonth = monthKey(new Date(now.getFullYear(), now.getMonth() - 1, 1));
  const env = bootApp([
    expense({ id: "1", amountCents: 1000, category: "Groceries", date: currentMonth + "-02" }),
    expense({ id: "2", amountCents: 2500, category: "Transport", date: currentMonth + "-03" }),
    expense({ id: "3", amountCents: 700, category: "Groceries", date: currentMonth + "-04" }),
    expense({ id: "4", amountCents: 9000, category: "Rent", date: previousMonth + "-01" })
  ]);

  assert.deepEqual(childTexts(env.elements.categoryTotals), [
    "Transport EUR 25.00",
    "Groceries EUR 17.00"
  ]);
});
test("downloads all expenses as escaped CSV regardless of the active filter", () => {
  const env = bootApp([
    expense({
      id: "1",
      amountCents: 550,
      category: "Utilities",
      date: "2026-07-04",
      note: "Line one\nLine two"
    }),
    expense({
      id: "2",
      amountCents: 1200,
      category: "Groceries",
      date: "2026-07-06",
      note: "Corner shop, bread"
    }),
    expense({
      id: "3",
      amountCents: 890,
      category: "Transport",
      date: "2026-07-05",
      note: 'He said "tram"'
    })
  ]);

  env.elements.categoryFilter.value = "Groceries";
  env.elements.categoryFilter.dispatchEvent({ type: "change" });

  env.elements.exportCsvButton.dispatchEvent({ type: "click" });

  assert.equal(env.downloads.length, 1);
  assert.match(env.downloads[0].download, /^pocketledger-expenses-\d{4}-\d{2}-\d{2}\.csv$/);
  assert.equal(env.downloads[0].type, "text/csv;charset=utf-8");
  assert.equal(env.downloads[0].text, [
    "Date,Category,Note,Amount (EUR)",
    '2026-07-06,Groceries,"Corner shop, bread",12.00',
    '2026-07-05,Transport,"He said ""tram""",8.90',
    '2026-07-04,Utilities,"Line one\nLine two",5.50'
  ].join("\r\n"));
});

function bootApp(expenses) {
  const document = new FakeDocument();
  const elements = createAppDom(document);
  const stored = new Map([["pocketledger.expenses.v1", JSON.stringify(expenses)]]);
  const objectUrls = new Map();
  const downloads = [];
  document.recordDownload = (anchor) => {
    const blob = objectUrls.get(anchor.href);
    downloads.push({
      download: anchor.download,
      href: anchor.href,
      text: blob.text,
      type: blob.type
    });
  };
  const window = {
    crypto: {
      randomUUID: () => "test-id"
    },
    localStorage: {
      getItem: (key) => stored.get(key) || null,
      setItem: (key, value) => {
        stored.set(key, value);
      }
    },
    URL: {
      createObjectURL: (blob) => {
        const url = "blob:test-" + String(objectUrls.size + 1);
        objectUrls.set(url, blob);
        return url;
      },
      revokeObjectURL: (url) => {
        objectUrls.delete(url);
      }
    }
  };

  const context = vm.createContext({
    Blob: FakeBlob,
    Date,
    document,
    window,
    Intl,
    setTimeout,
    clearTimeout
  });
  vm.runInContext(script, context);

  return { document, downloads, elements, stored };
}

function createAppDom(document) {
  const form = document.register(new FakeElement("form"));
  form.setAttribute("data-expense-form", "");
  document.register(form);

  return {
    form,
    amount: document.register(new FakeElement("input", "amount")),
    category: document.register(new FakeElement("input", "category")),
    date: document.register(new FakeElement("input", "date")),
    note: document.register(new FakeElement("input", "note")),
    formMessage: document.register(new FakeElement("p", "formMessage")),
    monthLabel: document.register(new FakeElement("span", "monthLabel")),
    monthTotal: document.register(new FakeElement("strong", "monthTotal")),
    expenseCount: document.register(new FakeElement("p", "expenseCount")),
    expenseRows: document.register(new FakeElement("tbody", "expenseRows")),
    tableWrap: document.register(new FakeElement("div", "tableWrap")),
    emptyState: document.register(new FakeElement("div", "emptyState")),
    categoryFilter: document.register(new FakeElement("select", "categoryFilter")),
    categoryTotals: document.register(new FakeElement("div", "categoryTotals")),
    exportCsvButton: document.register(new FakeElement("button", "exportCsvButton"))
  };
}

function expense(overrides) {
  return {
    id: "expense",
    amountCents: 100,
    category: "Other",
    date: "2026-07-01",
    note: "",
    createdAt: "2026-07-01T12:00:00.000Z",
    ...overrides
  };
}

function monthKey(date) {
  return date.getFullYear() + "-" + String(date.getMonth() + 1).padStart(2, "0");
}

function optionValues(select) {
  return select.children.map((option) => option.value);
}

function rowCategories(tbody) {
  return tbody.children.map((row) => row.children[1].textContent);
}

function childTexts(element) {
  return element.children.map((child) => child.textContent.replace(/\s+/g, " "));
}

class FakeDocument {
  constructor() {
    this.byId = new Map();
    this.expenseForm = null;
    this.body = new FakeElement("body");
    this.body.ownerDocument = this;
    this.recordDownload = null;
  }

  createElement(tagName) {
    const element = new FakeElement(tagName);
    element.ownerDocument = this;
    return element;
  }

  getElementById(id) {
    return this.byId.get(id) || null;
  }

  querySelector(selector) {
    if (selector === "[data-expense-form]") {
      return this.expenseForm;
    }

    return null;
  }

  register(element) {
    element.ownerDocument = this;
    if (element.id) {
      this.byId.set(element.id, element);
    }

    if (element.attributes["data-expense-form"] !== undefined) {
      this.expenseForm = element;
    }

    return element;
  }
}

class FakeElement {
  constructor(tagName, id = "") {
    this.tagName = tagName.toUpperCase();
    this.id = id;
    this.attributes = {};
    this.children = [];
    this.listeners = {};
    this.parentNode = null;
    this.hidden = false;
    this.className = "";
    this.title = "";
    this.download = "";
    this.href = "";
    this._textContent = "";
    this._innerHTML = "";
    this._value = "";
  }

  get textContent() {
    if (this._textContent) {
      return this._textContent;
    }

    return this.children.map((child) => child.textContent).join(" ");
  }

  set textContent(value) {
    this._textContent = String(value);
    this.children = [];
  }

  get innerHTML() {
    return this._innerHTML;
  }

  set innerHTML(value) {
    this._innerHTML = String(value);
  }

  get value() {
    return this._value;
  }

  set value(value) {
    this._value = String(value);
  }

  setAttribute(name, value) {
    this.attributes[name] = String(value);
    if (name === "id") {
      this.id = String(value);
    }
  }

  getAttribute(name) {
    return this.attributes[name] || null;
  }

  appendChild(child) {
    child.parentNode = this;
    this.children.push(child);
    return child;
  }

  removeChild(child) {
    this.children = this.children.filter((candidate) => candidate !== child);
    child.parentNode = null;
    return child;
  }

  replaceChildren(...children) {
    this.children = [];
    children.forEach((child) => this.appendChild(child));
  }

  addEventListener(type, handler) {
    this.listeners[type] = this.listeners[type] || [];
    this.listeners[type].push(handler);
  }

  dispatchEvent(event) {
    event.target = event.target || this;
    (this.listeners[event.type] || []).forEach((handler) => handler.call(this, event));
  }

  closest(selector) {
    if (selector !== "button[data-delete-id]") {
      return null;
    }

    var current = this;
    while (current) {
      if (current.tagName === "BUTTON" && current.getAttribute("data-delete-id")) {
        return current;
      }

      current = current.parentNode;
    }

    return null;
  }

  click() {
    if (this.tagName === "A" && this.ownerDocument.recordDownload) {
      this.ownerDocument.recordDownload(this);
    }

    this.dispatchEvent({ type: "click" });
  }

  focus() {}

  reset() {}
}

class FakeBlob {
  constructor(parts, options = {}) {
    this.text = parts.join("");
    this.type = options.type || "";
  }
}
